import torch
import torch.nn as nn
import torch.nn.functional as F

def conv2d(x: torch.Tensor, W: torch.Tensor, b: torch.Tensor,
           stride: int = 1, padding: int = 0) -> torch.Tensor:
    # Manual implementation with loops (for understanding)
    N, C_in, H, W_in = x.shape
    C_out, _, kH, kW = W.shape
    if padding > 0:
        x = F.pad(x, (padding, padding, padding, padding))
    H_pad, W_pad = x.shape[2], x.shape[3]
    H_out = (H_pad - kH) // stride + 1
    W_out = (W_pad - kW) // stride + 1
    out = torch.zeros(N, C_out, H_out, W_out, dtype=x.dtype)
    for n in range(N):
        for co in range(C_out):
            for i in range(H_out):
                for j in range(W_out):
                    h_s, w_s = i * stride, j * stride
                    patch = x[n, :, h_s:h_s+kH, w_s:w_s+kW]
                    out[n, co, i, j] = (patch * W[co]).sum() + b[co]
    return out

# Efficient version using PyTorch built-in:
# out = F.conv2d(x, W, b, stride=stride, padding=padding)

class Conv2d(nn.Module):
    def __init__(self, in_channels: int, out_channels: int,
                 kernel_size: int, stride: int = 1, padding: int = 0):
        super().__init__()
        self.conv = nn.Conv2d(in_channels, out_channels, kernel_size,
                              stride=stride, padding=padding)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.conv(x)
